MATCH
    p1 = (a:Entity {name: 'TIANSHENG INDUSTRY AND TRADING CO., LTD.'})-[:same_as]->(b:Entity),
    p2 = (a)-[:same_name_as]->(c:Other {name: 'ANTAM ENTERPRISES N.V.'})-[:same_id_as]->(d:Entity),
    p3 = (a)-[:same_as]->(e:Intermediary)-[:intermediary_of]->(f:Entity {name: 'ANTAM ENTERPRISES N.V.'})-[:same_company_as]->(g:Entity)
WHERE
    f.name = g.name
    AND EXISTS { (a)-[:registered_address]->(h:Address) }
    AND EXISTS { (e)-[:officer_of]->(i:Officer {name: 'OFFICER1'}) }
RETURN
    p1, p2, p3, a, b, c, d, e, f, g, h, i;

